# ── Ruleset compilation ──────────────────────────────────────────────────────

def _build_alt(patterns):
    return re.compile('|'.join('(?:' + p + ')' for p in patterns), re.IGNORECASE)

def compile_ruleset(data: Dict) -> Dict:
    rs = {
        'pill_rules':          data.get('pill_rules',          {}),
        'pregnancy_odds':      data.get('pregnancy_odds',      {}),
        'pregnancy_mechanics': data.get('pregnancy_mechanics',  {}),
        'effect_mechanics':    data.get('effect_mechanics',     {}),
        'state_schema':        data.get('state_schema',         {}),
        'state_events':        data.get('state_events',         {}),
        'roll_systems':        data.get('roll_systems',         {}),
        'counters':            data.get('counters',             []),
        'relationship_schema': data.get('relationship_schema',  {}),
        'personas':            data.get('personas',            {}),
        'stat_list':           data.get('stat_system',         {}).get('stats', []),
        'card_format':         data.get('card_format',         {}),
        'form_system':         data.get('form_system',         {}),
        'statgen_signals':     data.get('statgen_signals',     []),
        'card_scan':           data.get('card_scan',           {}),
        'body_result_tag':     data.get('body_result_tag',     {}),
        'display_flags':       data.get('display_flags',       []),
        'system_rules':        data.get('system_rules',        []),
        'engine_config':       data.get('engine_config',       {}),
        'pill_detection':      data.get('pill_detection',      {}),
        'arousal_system':      data.get('arousal_system',      {}),
        'orgasm_rules':        data.get('orgasm_rules',        {}),
        'directive_effects':   data.get('directive_effects',   []),
        'flavor_triggers':     [],
        'arousal_kw':          [],
        'pill_context_re':     None,
        'pill_noun_re':        None,
        'intake_verb_re':      None,
        'pill_offer_re':       None,
        'event_patterns_compiled': {},
    }

    raw_ft = data.get('flavor_triggers', {})
    rs['flavor_triggers'] = list(raw_ft.values()) if isinstance(raw_ft, dict) else raw_ft

    kw_weights = rs['arousal_system'].get('keyword_weights', {})
    for tier in kw_weights.values():
        w = float(tier.get('weight', 1))
        for kw in tier.get('keywords', []):
            try:
                rs['arousal_kw'].append((w, re.compile(r'\b' + re.escape(kw) + r'\b', re.IGNORECASE)))
            except Exception as _re_err:
                print(f'[WARN] arousal keyword pattern skipped: {kw!r} — {_re_err}')

    rs['arousal_action_kw'] = []
    for kw, w in rs['arousal_system'].get('user_action_weights', {}).items():
        try:
            rs['arousal_action_kw'].append((float(w), re.compile(r'\b' + re.escape(kw) + r'\b', re.IGNORECASE)))
        except Exception as _re_err:
            print(f'[WARN] action keyword pattern skipped: {kw!r} — {_re_err}')

    ep      = data.get('event_patterns', {})
    colors  = ep.get('pill_colors', [])
    nouns   = ep.get('pill_nouns',  [])
    intakes = ep.get('intake_verbs', [])
    brands  = ep.get('brand_names',  [])
    prox    = ep.get('pill_color_noun_proximity', 40)
    cp = '|'.join(re.escape(c) for c in colors)
    np = '|'.join(re.escape(n) for n in nouns)
    ip = '|'.join(re.escape(v) for v in intakes)
    bp = '|'.join(re.escape(b) for b in brands)
    if cp and np:
        ps = '.{0,' + str(prox) + '}'
        rs['pill_context_re'] = re.compile(
            r'\b(' + cp + r')\b' + ps + r'\b(' + np + r')\b'
            r'|\b(' + np + r')\b' + ps + r'\b(' + cp + r')\b', re.IGNORECASE)
        rs['pill_noun_re'] = re.compile(r'\b(' + np + r')\b', re.IGNORECASE)
    if ip:
        rs['intake_verb_re'] = re.compile(r'\b(' + ip + r')\b', re.IGNORECASE)
    if cp and np:
        # Match pill offer with or without asterisk roleplay formatting.
        # Requires color + pill noun within proximity. Brand name optional.
        rs['pill_offer_re'] = re.compile(
            r'\b(' + cp + r')\b.{0,' + str(prox) + r'}\b(?:' + np + r')\b'
            r'|\b(?:' + np + r')\b.{0,' + str(prox) + r'}\b(' + cp + r')\b',
            re.IGNORECASE)

    pd = data.get('pill_detection', {})
    neg_words  = pd.get('negation_words', [])
    fp_phrases = pd.get('intake_false_positives', [])
    # Ensure 'no' and 'back' are always in negation (catches "no take backs", etc.)
    for _w in ['no', 'back']:
        if _w not in neg_words:
            neg_words.append(_w)
    rs['pill_negation_re']  = re.compile(r'\b(' + '|'.join(re.escape(w) for w in neg_words) + r')\b', re.IGNORECASE) if neg_words else None
    rs['pill_false_pos_re'] = re.compile(r'^\s+(' + '|'.join(re.escape(p) for p in fp_phrases) + r')', re.IGNORECASE) if fp_phrases else None

    SKIP_EP = {'pill_colors', 'pill_nouns', 'brand_names', 'intake_verbs', 'pill_color_noun_proximity'}
    epc = {}
    for name, entry in ep.items():
        if name in SKIP_EP:
            continue
        if isinstance(entry, list):
            pats, source, req_flag, req_form = entry, 'all', None, False
        else:
            pats     = entry.get('patterns', [])
            source   = entry.get('source', 'all')
            req_flag = entry.get('requires_flag')
            req_form = bool(entry.get('requires_form_eligible', False))
        if pats:
            epc[name] = {'re': _build_alt(pats), 'source': source,
                         'requires_flag': req_flag, 'requires_form_eligible': req_form}
    rs['event_patterns_compiled'] = epc
    rs['body_modifiers']          = data.get('body_modifiers', {})
    rs['pill_descriptor_parsing'] = data.get('pill_descriptor_parsing', {})
    fp = rs['card_format'].get('field_patterns', {})
    rs['card_name_re']  = re.compile(fp.get('name',  r'^Name:\s*(.+?)\s*$'),  re.MULTILINE)
    rs['card_sex_re']   = re.compile(fp.get('sex',   r'^Sex:\s*(.+?)\s*$'),   re.MULTILINE)
    rs['card_stats_re'] = re.compile(fp.get('stats', r'^Stats:\s*(.+?)\s*$'), re.MULTILINE)
    return rs


# ── Card / system text helpers ───────────────────────────────────────────────

def _rx(pat, text):
    m = pat.search(text or '')
    return m.group(1).strip() if m else None

def extract_card_name(t,  rs=None): return _rx(rs['card_name_re']  if rs else re.compile(r'^Name:\s*(.+?)\s*$',  re.MULTILINE), t)
def extract_card_sex(t,   rs=None): return _rx(rs['card_sex_re']   if rs else re.compile(r'^Sex:\s*(.+?)\s*$',   re.MULTILINE), t)
def extract_card_stats(t, rs=None): return _rx(rs['card_stats_re'] if rs else re.compile(r'^Stats:\s*(.+?)\s*$', re.MULTILINE), t)

def _card_section(system_text):
    """Return the portion of system_text from the first 'Name:' line onwards."""
    m = re.search(r'^Name:\s*.+', system_text, re.MULTILINE | re.IGNORECASE)
    return system_text[m.start():] if m else system_text


# ── State schema / defaults ──────────────────────────────────────────────────

def default_state(rs=None):
    if rs and rs.get('state_schema'):
        import copy
        return copy.deepcopy(rs['state_schema'])
    return {
        'turn': 0, 'active_pill': None, 'active_effects': [],
        'flags': {}, 'stats': {}, 'roll_log': [],
        'effect_dcs': {}, 'effect_stages': {},
        'effect_locks': {}, 'arousal': 0.0, 'card_body': {},
    }


# ── Form / sex helpers ───────────────────────────────────────────────────────

def pill_rule(state, rs):
    p = state.get('active_pill')
    return rs['pill_rules'].get(p, {}) if p else {}

def _form_lookup(card_sex, rs):
    forms     = rs.get('form_system', {}).get('base_forms', {})
    sex_lower = (card_sex or '').lower().strip()
    for key, props in forms.items():
        if sex_lower == key:
            return props
    default = rs.get('form_system', {}).get('default_form', 'male')
    return forms.get(default, {})

def current_sex(state, card_sex, rs):
    rule = pill_rule(state, rs)
    if rule and not rule.get('no_form_change'):
        return rule.get('form_sex', card_sex).lower()
    return _form_lookup(card_sex, rs).get('form_sex_display', (card_sex or 'male').lower())

def current_genitals(state, card_sex, rs):
    rule = pill_rule(state, rs)
    if rule and not rule.get('no_form_change'):
        return rule.get('genitals', 'unknown')
    return _form_lookup(card_sex, rs).get('genitals', 'unknown')

def can_get_pregnant(state, card_sex, rs):
    rule = pill_rule(state, rs)
    if rule:
        return bool(rule.get('pregnancy_eligible'))
    return bool(_form_lookup(card_sex, rs).get('pregnancy_eligible'))


# ── Arousal helpers ──────────────────────────────────────────────────────────

def _arousal_scale(rs):
    return float(rs['arousal_system'].get('formula', {}).get('scale', 100.0))

def get_arousal(state):
    return float(state.get('arousal', 0.0))

def get_arousal_floor(state, rs):
    em = rs['effect_mechanics']
    floor = 0.0
    for eff_name, mech in em.items():
        tb = mech.get('trigger_behavior', {})
        if not tb.get('arousal_floor'):
            continue
        stage  = state.get('effect_stages', {}).get(eff_name, 0)
        floors = rs['arousal_system'].get('addiction_floor', {})
        floor  = max(floor, float(floors.get('stage_' + str(stage), 0)))
    return floor

def set_arousal(state, value, rs):
    floor = get_arousal_floor(state, rs)
    mx    = float(rs['arousal_system'].get('max', 60))
    state['arousal'] = round(max(floor, min(mx, float(value))), 2)

def grow_arousal(state, weight, rs):
    """Grow arousal by weight, with a tier gate every 5 levels.

    Tier boundaries are at 5, 10, 15, 20, 25, … Max +1 tier advance per turn.
    When arousal would cross the next tier boundary:
      - If gate already rolled this turn: cap at current boundary.
      - Otherwise: d6 → pick stat, d20 + stat_mod vs DC.
        PASS → arousal stays just below boundary (held).
        FAIL → arousal advances to boundary + negative block from d6 stat.

    Per-boundary DCs escalate by dc_step after each attempt (pass or fail).
    state['_arousal_gate_done'] tracks whether the gate already fired this turn.
    Cleared at the start of each turn in process_turn.
    """
    TIER_SIZE = 5
    scale     = _arousal_scale(rs)
    current   = get_arousal(state)
    proposed  = current + weight * (1.0 + current / scale)

    # Next tier boundary above current position
    current_tier  = int(current) // TIER_SIZE
    next_boundary = (current_tier + 1) * TIER_SIZE

    # If we don't cross a boundary, just set it (capped at boundary if gate held)
    gate_done = state.get('_arousal_gate_done')

    if gate_done == 'held':
        # Already held this turn — cap just below the boundary
        set_arousal(state, min(proposed, float(next_boundary) - 0.01), rs)
        return

    if gate_done == 'crossed':
        # Already crossed one tier this turn — cap at the boundary we crossed to
        crossed_to = state.get('_arousal_gate_crossed_to', next_boundary)
        set_arousal(state, min(proposed, float(crossed_to)), rs)
        return

    if proposed < next_boundary:
        # No boundary crossed, no gate needed
        set_arousal(state, proposed, rs)
        return

    # ── Gate roll ────────────────────────────────────────────────────────────
    t_key    = str(next_boundary)
    base_dc  = int(rs['arousal_system'].get('level_gate_dc', 11))
    dc_store = state.setdefault('_arousal_gate_dcs', {})
    dc       = dc_store.get(t_key, base_dc)

    # d6 → pick stat
    d6_raw   = random.randint(1, 6)
    d6_stat  = D6_STAT_MAP[d6_raw]
    mod_val  = _mod(state, d6_stat)

    # d20 + stat mod vs DC
    raw_roll = random.randint(1, 20)
    total    = raw_roll + mod_val
    passed   = total >= dc

    # DC escalates by 1 on fail only; total fails tracked for downstream use
    if not passed:
        dc_store[t_key] = dc + 1
        state['_arousal_gate_fail_count'] = state.get('_arousal_gate_fail_count', 0) + 1

    # Build gate record for debug display
    gate = {
        'roll':      raw_roll,
        'd6':        d6_raw,
        'd6_stat':   d6_stat,
        'mod':       mod_val,
        'total':     total,
        'dc':        dc,
        'threshold': next_boundary,
    }

    # Determine the arousal tier for negative block band
    arousal_tier = next_boundary // TIER_SIZE

    if passed:
        gate['result'] = 'held'
        state['_arousal_gate']      = gate
        state['_arousal_gate_done'] = 'held'
        entry = ('arousal_gate:PASS(d6=' + str(d6_raw) + '->' + d6_stat
                 + ' d20=' + str(raw_roll) + ('+' if mod_val >= 0 else '') + str(mod_val)
                 + '=' + str(total) + ' vs DC=' + str(dc)
                 + ' tier=' + str(next_boundary) + ' HELD)')
        state.setdefault('roll_log', []).append(entry)
        set_arousal(state, float(next_boundary) - 0.01, rs)
    else:
        gate['result'] = 'crossed'
        state['_arousal_gate']          = gate
        state['_arousal_gate_done']     = 'crossed'
        state['_arousal_gate_crossed_to'] = next_boundary

        # Negative block from the d6-picked stat
        band     = _neg_tier_band(arousal_tier)
        card_sex = state.get('_card_sex', 'female')
        eff_sex  = current_sex(state, card_sex, rs)
        neg_text = _NEGATIVE_BLOCKS.get(d6_stat, {}).get(band, {}).get(eff_sex, '')
        gate['neg_block'] = neg_text

        entry = ('arousal_gate:FAIL(d6=' + str(d6_raw) + '->' + d6_stat
                 + ' d20=' + str(raw_roll) + ('+' if mod_val >= 0 else '') + str(mod_val)
                 + '=' + str(total) + ' vs DC=' + str(dc)
                 + ' tier=' + str(next_boundary) + ' CROSSED)')
        state.setdefault('roll_log', []).append(entry)
        set_arousal(state, float(next_boundary), rs)

def arousal_label(level, rs):
    thresholds = rs['arousal_system'].get('thresholds', {})
    label = 'baseline'
    for k in sorted(thresholds.keys(), key=lambda x: int(x)):
        if level >= int(k):
            label = thresholds[k].get('label', label)
    return label

def arousal_roll_penalty(state, rs):
    level   = get_arousal(state)
    pen_cfg = rs['arousal_system'].get('arousal_roll_penalty', {}).get('thresholds', {})
    penalty = 0
    for k in sorted(pen_cfg.keys(), key=lambda x: int(x)):
        if level >= int(k):
            v = pen_cfg[k]
            if v == 'auto_fail':
                return 'auto_fail'
            penalty = int(v)
    return penalty

def apply_effect_passives(state, rs, debug=False):
    """Apply per-turn passive arousal gains from active effects."""
    em = rs.get('effect_mechanics', {})
    for eff in state.get('active_effects', []):
        gain = float(em.get(eff, {}).get('passive_arousal_per_turn', 0))
        if gain:
            grow_arousal(state, gain, rs)
            if debug:
                print('[AROUSAL] passive +' + str(gain) + ' from ' + eff)


def scan_arousal(messages_recent, state, rs, debug=False):
    cap       = float(rs['arousal_system'].get('scan_cap', 999.0))
    gained    = 0.0
    hits      = []
    action_kw = rs.get('arousal_action_kw', [])
    for msg in messages_recent:
        text = msg.get('content') or ''
        role = (msg.get('role') or '').lower()
        # Character response words — assistant messages ONLY.
        # The character's own prose reflects their arousal state.
        # Persona messages must not self-escalate the character via narrative;
        # that lane belongs exclusively to action_kw below.
        if role == 'assistant':
            for weight, pat in rs['arousal_kw']:
                if pat.search(text) and gained < cap:
                    before = get_arousal(state)
                    grow_arousal(state, weight, rs)
                    gained += get_arousal(state) - before
                    hits.append(re.sub(r'^\\b|\\b$', '', pat.pattern) + '(+' + str(weight) + ')')
        # User / persona action words — user messages only
        if role == 'user' and action_kw:
            for weight, pat in action_kw:
                if pat.search(text) and gained < cap:
                    before = get_arousal(state)
                    grow_arousal(state, weight, rs)
                    gained += get_arousal(state) - before
                    hits.append(re.sub(r'^\\b|\\b$', '', pat.pattern) + '[act+' + str(weight) + ']')
    if debug and hits:
        print('[AROUSAL] +' + str(round(gained, 2)) + ' from: ' + ', '.join(hits))
    elif debug:
        print('[AROUSAL] no keywords matched')

def apply_arousal_decay(state, rs):
    no_decay = set(rs['arousal_system'].get('no_decay_effects', []))
    if any(e in no_decay for e in state.get('active_effects', [])):
        return
    decay = float(rs['arousal_system'].get('passive_decay', 0.0))
    if decay > 0 and get_arousal(state) > 0:
        set_arousal(state, get_arousal(state) - decay, rs)


# ── Effect state helpers ─────────────────────────────────────────────────────

def get_effect_dc(state, name, rs):
    mech = rs['effect_mechanics'].get(name, {})
    return state.setdefault('effect_dcs', {}).setdefault(name, int(mech.get('start_dc', 12)))

def set_effect_dc(state, name, dc):
    state.setdefault('effect_dcs', {})[name] = dc

def get_effect_stage(state, name):
    return state.setdefault('effect_stages', {}).get(name, 0)

def set_effect_stage(state, name, stage):
    state.setdefault('effect_stages', {})[name] = stage

def is_locked(state, name):
    return bool(state.setdefault('effect_locks', {}).get(name, False))

def lock_effect(state, name):
    state.setdefault('effect_locks', {})[name] = True

def get_stat_mod(state, key):
    return int((state.get('stats') or {}).get(key, 0))

def compute_mods(state, roll_list):
    total = 0
    for item in (roll_list or []):
        item = item.strip()
        sign = -1 if item.startswith('-') else 1
        item = item.lstrip('+-')
        total += sign * get_stat_mod(state, item)
    return total

def check_math_lock(state, name, rs):
    mech     = rs['effect_mechanics'].get(name, {})
    max_roll = 20 + compute_mods(state, mech.get('roll', []))
    if get_effect_dc(state, name, rs) > max_roll:
        lock_effect(state, name)
        return True
    return False


# ── Roll system ──────────────────────────────────────────────────────────────

def run_roll(state, name, notes, rs):
    if is_locked(state, name):
        notes.append(name + ':LOCKED')
        return 'locked'

    mech        = rs['effect_mechanics'].get(name, {})
    roll_list   = mech.get('roll', [])
    mods        = compute_mods(state, roll_list)
    current_dc  = get_effect_dc(state, name, rs)
    escalation  = int(mech.get('escalation', 2))
    escalate_on = mech.get('escalate_on', 'pass')

    ar_pen = arousal_roll_penalty(state, rs)
    if ar_pen == 'auto_fail':
        notes.append(name + ':auto-fail(arousal=max)')
        return 'fail'
    mods += ar_pen

    max_possible = 20 + mods
    if max_possible < current_dc:
        lock_effect(state, name)
        notes.append(name + ':LOCKED(max=' + str(max_possible) + '<DC=' + str(current_dc) + ')')
        return 'locked'

    roll   = random.randint(1, 20)
    total  = roll + mods
    passed = total >= current_dc
    tag    = 'PASS' if passed else 'FAIL'
    entry  = name + ':' + tag + '(d20=' + str(roll) + ('+' if mods >= 0 else '') + str(mods) + '=' + str(total) + ' vs DC=' + str(current_dc) + ')'
    notes.append(entry)
    state.setdefault('roll_log', []).append(entry)
    print('[ROLL] ' + name + ' ' + tag + ' d20=' + str(roll) + ' mods=' + str(mods) + ' total=' + str(total) + ' dc=' + str(current_dc))

    if passed and escalate_on == 'pass':
        set_effect_dc(state, name, current_dc + escalation)
        check_math_lock(state, name, rs)
    if not passed and escalate_on == 'fail':
        set_effect_dc(state, name, current_dc + escalation)
        check_math_lock(state, name, rs)

    tb      = mech.get('trigger_behavior', {})
    tb_log  = tb.get('on_pass') if passed else tb.get('on_fail')
    if tb_log:
        notes.append(tb_log)

    return 'pass' if passed else 'fail'

def advance_stage(state, name, notes, rs, to_db=False):
    mech      = rs['effect_mechanics'].get(name, {})
    stages    = mech.get('stages', {})
    current   = get_effect_stage(state, name)
    max_stage = len(stages)
    if current >= max_stage:
        return
    new_stage  = current + 1
    set_effect_stage(state, name, new_stage)
    stage_info = stages.get(str(new_stage), {})
    notes.append(name + ' stage->' + str(new_stage) + ': ' + stage_info.get('note', ''))
    stats      = state.setdefault('stats', {})
    ec         = (rs or {}).get('engine_config', {})
    pen_suffix = ec.get('stage_penalty_suffix', '_penalty')
    perm_prefix = ec.get('perm_stage_flag_prefix', 'perm_')
    for sk, sv in stage_info.items():
        if sk.endswith(pen_suffix):
            base = sk[:-len(pen_suffix)].upper() + '_mod'
            stats[base] = int(stats.get(base, 0)) + int(sv)
            notes.append(base + '=' + str(stats[base]))
    if stage_info.get('permanent') or new_stage >= max_stage:
        lock_effect(state, name)
        notes.append(name + ':permanent stage=' + str(new_stage))
        if to_db:
            state.setdefault('flags', {})[perm_prefix + name + '_stage'] = new_stage

def roll_pregnancy(effects, rs):
    odds    = rs['pregnancy_odds']
    ft      = rs['flavor_triggers']
    ft_dict = {f['effect']: f for f in ft if isinstance(f, dict)}
    modes   = set()
    for eff in effects:
        f = ft_dict.get(eff, {})
        if f.get('pregnancy_mode'):
            modes.add(f['pregnancy_mode'])
    em = rs['effect_mechanics']
    for eff in effects:
        tb = em.get(eff, {}).get('trigger_behavior', {})
        pm = tb.get('pregnancy_partner_mode')
        if pm:
            modes.add(pm)
    chance = int(odds.get('normal', 4))
    for entry in odds.get('role_priority', []):
        if all(r in modes for r in entry.get('roles', [])):
            chance = int(odds.get(entry['key'], chance))
            break
    roll   = random.randint(1, 100)
    result = roll <= chance
    print('[PREG] d100=' + str(roll) + ' need<=' + str(chance) + ' => ' + ('YES' if result else 'no'))
    return result, roll, chance


# ── Body / card scanning ─────────────────────────────────────────────────────

def scan_card_body(system_text, rs=None):
    text = _card_section(system_text)
    body = {}
    for mp in (rs or {}).get('card_scan', {}).get('measurement_patterns', []):
        m = re.search(mp['pattern'], text, re.IGNORECASE)
        if not m:
            continue
        fmt = mp.get('format', '')
        if fmt == 'feet_inches':
            body['height_ft']  = int(m.group(1))
            body['height_in']  = int(m.group(2))
            body['height_str'] = m.group(1) + "'" + m.group(2) + '"'
        elif fmt == 'lbs':
            body['weight'] = int(m.group(1))
        else:
            body[mp['key']] = m.group(1)
    build_kws = (rs or {}).get('card_scan', {}).get('build_keywords', [])
    found = [k for k in build_kws if re.search(r'\b' + k + r'\b', text, re.IGNORECASE)]
    if found:
        body['build_keywords'] = found
    return body

def parse_pill_descriptor(pill_context_text, rs):
    text_lower = pill_context_text.lower()
    result = {'color': None, 'body_modifier': None, 'effects': []}
    for color in rs['pill_rules'].keys():
        if color in text_lower:
            result['color'] = color
            break
    modifiers = rs['pill_descriptor_parsing'].get('modifier_keywords', [])
    for mod in modifiers:
        if mod in text_lower:
            result['body_modifier'] = mod
            break
    for ft in rs['flavor_triggers']:
        for kw in ft.get('keywords', []):
            if kw in text_lower:
                if ft['effect'] not in result['effects']:
                    result['effects'].append(ft['effect'])
                break
    return result

def get_body_guidance(color, modifier, card_body, rs):
    bm       = rs['body_modifiers']
    fallback = bm.get(color, {}).get('fallback_modifier_color', color)
    color_entry = bm.get(color) or bm.get(fallback, {})
    baseline_parts = []
    if card_body.get('height_str'):
        baseline_parts.append('height ' + card_body['height_str'])
    if card_body.get('weight'):
        baseline_parts.append(str(card_body['weight']) + 'lbs')
    if card_body.get('build_keywords'):
        baseline_parts.append(', '.join(card_body['build_keywords'][:3]))
    baseline_str = 'Starting body: ' + (', '.join(baseline_parts) if baseline_parts else 'unknown')
    _SKIP_MOD_KEYS = {'transformation_guidance', 'modifiers', 'baseline_from_card', 'fallback_modifier_color'}
    if modifier:
        mod_entry = color_entry.get('modifiers', {}).get(modifier)
        if mod_entry:
            target_parts = ['Target body (' + modifier + ')']
            for k, v in mod_entry.items():
                if k not in _SKIP_MOD_KEYS:
                    target_parts.append(k + ': ' + str(v))
            return baseline_str + '\n' + ' | '.join(target_parts)
    baseline    = color_entry.get('baseline_from_card', {})
    rules       = baseline.get('rules', [])
    scale_label = baseline.get('scale_label', 'Target body: scale from character baseline')
    target_parts = [scale_label]
    if rules:
        target_parts.extend(rules[:2])
    return baseline_str + '\n' + ' | '.join(target_parts)


# ── Body result tag ──────────────────────────────────────────────────────────

def _body_result_re(rs):
    tag_name = (rs or {}).get('body_result_tag', {}).get('name', 'BODY_RESULT')
    return re.compile(r'\[' + re.escape(tag_name) + r':\s*([^\]]+)\]', re.IGNORECASE)

def parse_body_result_tag(text, rs=None):
    m = _body_result_re(rs).search(text or '')
    if not m:
        return None
    result = {}
    for part in m.group(1).split(','):
        part = part.strip()
        if '=' in part:
            k, _, v = part.partition('=')
            k = k.strip().lower()
            v = v.strip().strip('"').strip("'")
            if k and v:
                result[k] = v
    return result if result else None

def strip_body_result_tag(text, rs=None):
    return _body_result_re(rs).sub('', text).rstrip()


# ── Transformation guidance ──────────────────────────────────────────────────

def build_transformation_guidance(pill_descriptor, card_body, card_sex, rs):
    color    = pill_descriptor.get('color', 'unknown')
    modifier = pill_descriptor.get('body_modifier')
    effects  = pill_descriptor.get('effects', [])
    pdr      = rs['pill_descriptor_parsing']
    p_rule   = rs['pill_rules'].get(color, {})
    from_sex = (card_sex or 'unknown').lower()
    to_sex   = p_rule.get('form_sex', 'unknown')
    genitals = p_rule.get('genitals', 'unknown')
    no_change = p_rule.get('no_form_change', False)

    direction = ('Effects only — no body transformation' if no_change else
                 'Transformation: ' + from_sex + ' -> ' + to_sex + ' | genitals: -> ' + genitals.replace('_', ' '))

    bm        = rs['body_modifiers']
    bm_color  = bm.get(color, {}).get('fallback_modifier_color', color)
    color_tg  = (bm.get(color, {}).get('transformation_guidance') or
                 bm.get(bm_color, {}).get('transformation_guidance', {}))
    banner          = color_tg.get('direction_banner')
    narration_order = color_tg.get('narration_order') or pdr.get('transformation_narration_order', [])
    narration_rules = pdr.get('narration_rules', [])
    body_guidance   = get_body_guidance(color, modifier, card_body, rs)

    lines = [
        'TRANSFORMATION GUIDANCE (this turn only):',
        'Pill: ' + color + (' + ' + modifier if modifier else '') +
            (' | effects: ' + ', '.join(effects) if effects else ''),
        direction,
    ]
    if not no_change:
        if banner:
            lines.append(banner)
        lines.append(body_guidance)
        lines.append('Narration order: ' + ' -> '.join(narration_order))
        for rule in narration_rules:
            lines.append(rule)
        genitals_key = p_rule.get('genitals', '')
        for eff, ea in rs['body_modifiers'].get('effect_anatomy', {}).items():
            if eff not in effects:
                continue
            required = ea.get('requires_genitals', [])
            if required and genitals_key not in required:
                continue
            note = ea.get('transformation_note', '').strip()
            if note:
                lines.append(note)
        lines.append("State the final height, weight, and bust size as specific numbers within the narrative prose (e.g. 5'2\", 105lbs, B-cup).")
    return '\n'.join(lines)


# ── Pill detection ───────────────────────────────────────────────────────────

def find_pill_ingest(messages_recent, rs, state=None):
    """
    Scan messages for pill intake.
    - If a pill offer is seen, store it in state['_pending_pill'].
    - If an intake verb is seen and state has a pending pill, fire on that pill.
    - No requirement that color and intake verb appear in the same message.
    """
    offer_re    = rs.get('pill_offer_re')
    intake_re   = rs.get('intake_verb_re')
    negation_re = rs.get('pill_negation_re')
    false_pos_re = rs.get('pill_false_pos_re')
    if not offer_re or not intake_re:
        return None, [], None

    # Seed pending from persisted state
    pending_color = (state or {}).get('_pending_pill')
    pending_text  = (state or {}).get('_pending_pill_text')

    for msg in messages_recent:
        text = (msg.get('content') or '').strip()
        role = (msg.get('role') or '').lower()
        if not text:
            continue

        # Update pending pill whenever an offer is seen
        m = offer_re.search(text)
        if m:
            # color may be in group 1 or group 2 depending on which arm matched
            color = (m.group(1) or m.group(2) or '').lower()
            if color and color != pending_color:
                pending_color = color
                pending_text  = m.group(0)
                if state is not None:
                    desc = parse_pill_descriptor(pending_text, rs)
                    desc['color'] = pending_color
                    state['_pending_pill']      = pending_color
                    state['_pending_pill_desc'] = desc
                    state.pop('_pending_pill_text', None)

        # Intake: only fire on user messages — assistant dialogue must never consume the pill
        if pending_color and role == 'user' and intake_re.search(text):
            ingested = False
            for vm in intake_re.finditer(text):
                pre  = text[max(0, vm.start()-40):vm.start()]
                post = text[vm.end():min(len(text), vm.end()+40)]
                if negation_re and (negation_re.search(pre) or negation_re.search(post)):
                    continue
                if false_pos_re and false_pos_re.match(post):
                    continue
                ingested = True; break
            if ingested:
                # Clear pending from state — pill is now consumed
                if state is not None:
                    state.pop('_pending_pill', None)
                    state.pop('_pending_pill_text', None)
                return pending_color, list(messages_recent), pending_text

    return None, [], None

def parse_pill_from_ingest(messages_recent, rs, state=None, debug=False):
    color, context, stored_desc_text = find_pill_ingest(messages_recent, rs, state=state)
    if not color:
        return None, None
    # Use pre-parsed descriptor from state if available, else parse now
    descriptor = (state or {}).pop('_pending_pill_desc', None)
    if not descriptor:
        pill_phrase = stored_desc_text or color
        descriptor  = parse_pill_descriptor(pill_phrase, rs)
        descriptor['color'] = color
    if debug:
        print('[PILL] effects: ' + str(descriptor.get('effects')))
    return color, descriptor


# ── Event detection ──────────────────────────────────────────────────────────

def detect_events(messages_recent, state, card_sex, rs, debug=False):
    events   = {}
    all_text = '\n'.join((m.get('content') or '') for m in messages_recent)
    user_text = '\n'.join(
        (m.get('content') or '') for m in messages_recent if m.get('role') == 'user'
    )
    # Most recent user message only — for one-shot events that must not repeat
    last_user_text = next(
        ((m.get('content') or '') for m in reversed(messages_recent) if m.get('role') == 'user'), ''
    )

    if not state.get('active_pill'):
        color, descriptor = parse_pill_from_ingest(messages_recent, rs, state=state, debug=debug)
        if color:
            events['pill_taken']      = color
            events['pill_descriptor'] = descriptor
            if descriptor:
                if descriptor.get('body_modifier'):
                    state['_pending_body_modifier'] = descriptor['body_modifier']
                for eff in descriptor.get('effects', []):
                    events['flavor_' + eff] = True

    active_effects = state.get('active_effects') or []
    for ft in rs['flavor_triggers']:
        if ft.get('requires_pill'):
            continue
        if ft['effect'] in active_effects:
            continue
        for kw in ft.get('keywords', []):
            if re.search(r'\b' + re.escape(kw) + r'\b', all_text, re.IGNORECASE):
                events['flavor_' + ft['effect']] = True
                break

    temp = dict(state)
    if events.get('pill_taken'):
        temp['active_pill'] = events['pill_taken']

    for event_name, compiled in rs.get('event_patterns_compiled', {}).items():
        # user_only events check ONLY the most recent user message to prevent
        # the same message re-matching across multiple turns in the scan window
        if compiled['source'] in ('user_only', 'last_user'):
            text = last_user_text
        elif compiled['source'] == 'last_assistant':
            text = next(((m.get('content') or '') for m in reversed(messages_recent) if m.get('role') == 'assistant'), '')
        else:
            text = all_text
        if not compiled['re'].search(text):
            continue
        if compiled['requires_form_eligible']:
            if not can_get_pregnant(temp, card_sex, rs):
                if debug:
                    print('[EVENT] ' + event_name + ' not eligible (form)')
                continue
        req_flag = compiled['requires_flag']
        if req_flag and not state.get('flags', {}).get(req_flag):
            continue
        events[event_name] = True

    return events


# ── Generic state executors ──────────────────────────────────────────────────

def _resolve_birth_dc(dc_src, state, rs):
    mechanic     = dc_src.get('mechanic')
    stage_effect = dc_src.get('stage_effect')
    pm           = rs.get('pregnancy_mechanics', {})
    mech_def     = pm.get(mechanic, {})
    dc_table     = mech_def.get('dc_by_stage', {})
    stage        = state.get('effect_stages', {}).get(stage_effect, 0)
    return dc_table.get(str(stage), 'impossible')

def _execute_effect_birth(state, effects, notes, rs):
    flags = state.setdefault('flags', {})
    em    = rs.get('effect_mechanics', {})
    for eff_name in list(effects):
        mech = em.get(eff_name, {})
        ob   = mech.get('on_birth')
        if not ob:
            continue
        if ob.get('roll'):
            attempt_key = ob.get('attempt_counter', '')
            attempt     = state.get(attempt_key, 0) if attempt_key else 0
            dc          = _resolve_birth_dc(ob.get('dc_source', {}), state, rs)
            if dc == 'impossible':
                notes.append(eff_name + ':revert impossible(permanent)')
                impossible_flag = ob.get('impossible_set_flag_false', '')
                if impossible_flag:
                    flags[impossible_flag] = False
                continue
            pm_data  = rs.get('pregnancy_mechanics', {})
            pb       = pm_data.get(ob['dc_source'].get('mechanic', 'post_birth_revert'), {})
            escalate = int(pb.get('attempt_escalation', 4))
            final_dc = int(dc) + (attempt * escalate)
            mods     = compute_mods(state, ob.get('roll', ['WIS_mod', 'CON_mod']))
            roll     = random.randint(1, 20)
            total    = roll + mods
            passed   = total >= final_dc
            state[attempt_key] = attempt + 1
            tag = 'PASS' if passed else 'FAIL'
            entry = eff_name + ':birth_roll:' + tag + '(d20=' + str(roll) + ('+' if mods >= 0 else '') + str(mods) + '=' + str(total) + ' vs DC=' + str(final_dc) + ')'
            notes.append(entry)
            state.setdefault('roll_log', []).append(entry)
            print('[BIRTH] ' + eff_name + ' revert ' + tag + ' roll=' + str(total) + ' dc=' + str(final_dc))
            result = ob['on_pass'] if passed else ob['on_fail']
        else:
            result = ob
        if result.get('remove_self'):
            effects[:] = [e for e in effects if e != eff_name]
            state['active_effects'] = list(effects)
        for comp in result.get('remove_companions', []):
            if comp in effects:
                effects[:] = [e for e in effects if e != comp]
                state['active_effects'] = list(effects)
        for f in result.get('set_flags', []):
            flags[f] = True
        if 'set_flag_false' in result:
            flags[result['set_flag_false']] = False
        if result.get('reset_arousal'):
            set_arousal(state, 0.0, rs)
        for k in result.get('clear_effect_dcs', []):
            state.setdefault('effect_dcs', {}).pop(k, None)
        for k in result.get('clear_effect_locks', []):
            state.setdefault('effect_locks', {}).pop(k, None)
        if result.get('log'):
            notes.append(result['log'])

def _run_roll_system(name, state, effects, notes, rs):
    sys_def = rs.get('roll_systems', {}).get(name)
    if not sys_def:
        return
    flags        = state.setdefault('flags', {})
    already_flag = sys_def.get('already_active_flag')
    if already_flag and flags.get(already_flag):
        if sys_def.get('already_active_log'):
            notes.append(sys_def['already_active_log'])
        return
    odds_src = sys_def.get('odds_source')
    if odds_src == 'pregnancy_odds':
        success, preg_roll, preg_need = roll_pregnancy(effects, rs)
        entry = name + ':d100=' + str(preg_roll) + ' need<=' + str(preg_need) + (' CONCEIVED' if success else ' no')
        notes.append(entry)
        state.setdefault('roll_log', []).append(entry)
    elif sys_def.get('roll'):
        dc      = int(sys_def.get('dc', 12))
        mods    = compute_mods(state, sys_def['roll'])
        roll    = random.randint(1, 20)
        total   = roll + mods
        success = total >= dc
        tag     = 'PASS' if success else 'FAIL'
        entry   = name + ':' + tag + '(d20=' + str(roll) + ('+' if mods >= 0 else '') + str(mods) + '=' + str(total) + ' vs DC=' + str(dc) + ')'
        notes.append(entry)
        state.setdefault('roll_log', []).append(entry)
    else:
        success = False
    result = sys_def['on_success'] if success else sys_def['on_fail']
    for f in result.get('set_flags', []):
        flags[f] = True
    cif = result.get('conceived_if_effect', {})
    if success and cif and cif.get('effect') in effects:
        flags[cif['set_flag']] = True
        if cif.get('log'):
            notes.append(cif['log'])
    if result.get('log'):
        notes.append(result['log'])

def _process_counters(state, events, effects, rs):
    for counter in rs.get('counters', []):
        key     = counter['key']
        trigger = counter['trigger']
        if not events.get(trigger):
            continue
        req_effects = counter.get('requires_any_effect', [])
        if req_effects and not any(e in effects for e in req_effects):
            continue
        state[key] = state.get(key, 0) + 1

def _execute_state_events(event_name, state, events, effects, notes, rs):
    actions = rs.get('state_events', {}).get(event_name, [])
    if not actions:
        return
    if not actions:
        return
    flags = state.setdefault('flags', {})
    for act in actions:
        cond = act.get('condition', {})
        if cond:
            if 'flag_true'  in cond and not flags.get(cond['flag_true']):
                continue
            if 'flag_false' in cond and flags.get(cond['flag_false']):
                continue
        blocked = False
        if act.get('block_if_flag') and flags.get(act['block_if_flag']):
            if act.get('block_log'):
                notes.append(act['block_log'])
            blocked = True
        if not blocked and 'block_if_pill_rule_false' in act:
            p_rule = rs['pill_rules'].get(state.get('active_pill') or '', {})
            if not p_rule.get(act['block_if_pill_rule_false'], True):
                if act.get('block_pill_log'):
                    notes.append(act['block_pill_log'])
                blocked = True
        if blocked:
            continue
        if 'increment' in act:
            key = act['increment']
            state[key] = state.get(key, 0) + 1
            if act.get('log'):
                try:    notes.append(act['log'].format_map(state))
                except: notes.append(act['log'])
        if 'set_flag'  in act: flags[act['set_flag']]  = True
        if 'set_flags' in act:
            for f in act['set_flags']: flags[f] = True
        if 'set_flag_false' in act: flags[act['set_flag_false']] = False
        if 'clear_flags'    in act:
            for f in act['clear_flags']: flags[f] = False
        if 'reset' in act:
            for k, v in act['reset'].items(): state[k] = v
        if act.get('action') == 'clear_pill':
            state['active_pill'] = None
            if act.get('clear_effects'):
                state['active_effects'] = []
                effects.clear()
            if act.get('reset_arousal'):
                set_arousal(state, 0.0, rs)
        if 'roll_system' in act:
            cond = act.get('condition', {})
            if cond.get('effect_active') and cond['effect_active'] not in effects:
                continue
            _run_roll_system(act['roll_system'], state, effects, notes, rs)
        if act.get('trigger_effect_birth'):
            _execute_effect_birth(state, effects, notes, rs)
        if act.get('log') and 'increment' not in act:
            notes.append(act['log'])

def process_events(state, events, card_sex, notes, rs):
    em      = rs['effect_mechanics']
    effects = list(state.get('active_effects') or [])
    state.pop('_notes_log', None)  # clear previous turn

    if events.get('pill_taken'):
        color = events['pill_taken']
        rule  = rs['pill_rules'].get(color, {})
        state['active_pill'] = color
        for eff in rule.get('immediate_effects', []):
            if eff not in effects:
                effects.append(eff)
        fn = 'effects only' if rule.get('no_form_change') else \
             'form=' + rule.get('form_sex', '?') + ' genitals=' + rule.get('genitals', '?')
        notes.append('Pill:' + color + '(' + fn + ') transforms immediately')
        state['_pill_descriptor_this_turn'] = {
            'color':         color,
            'body_modifier': state.get('_pending_body_modifier'),
            'effects':       list(effects)
        }
        state.pop('_pending_body_modifier', None)

    newly_added = set()
    for ft in rs['flavor_triggers']:
        key = 'flavor_' + ft['effect']
        if events.get(key) and ft['effect'] not in effects:
            effects.append(ft['effect'])
            newly_added.add(ft['effect'])
            mech = em.get(ft['effect'], {})
            state.setdefault('effect_dcs', {})[ft['effect']] = int(mech.get('start_dc', 12))
            notes.append('Effect:' + ft['effect'])
            for companion in mech.get('companion_effects', []):
                if companion not in effects:
                    effects.append(companion)
                    newly_added.add(companion)
                    cmech = em.get(companion, {})
                    state.setdefault('effect_dcs', {})[companion] = int(cmech.get('start_dc', 12))
                    notes.append('Effect:' + companion + '(companion)')
    state['active_effects'] = effects

    ec               = rs.get('engine_config', {})
    orgasm_ev        = ec.get('orgasm_event', 'orgasm')
    denied_ev        = ec.get('denied_event', 'orgasm_denied')
    orgasm_this_turn = events.get(orgasm_ev, False)
    denied_this_turn = events.get(denied_ev, False)

    orgasm_rules = rs['orgasm_rules'].get('gates', {})
    for eff_name, gate in orgasm_rules.items():
        if eff_name not in effects:
            continue
        req_event = gate.get('requires_event')
        if req_event and not events.get(req_event):
            if gate.get('denied_otherwise') and orgasm_this_turn:
                denied_this_turn = True
                notes.append(eff_name + ':orgasm denied by mechanic(requires ' + req_event + ')')
        elif req_event and events.get(req_event):
            orgasm_this_turn = True
            arousal_reset = gate.get('arousal_reset_on')
            if arousal_reset and events.get(arousal_reset):
                set_arousal(state, 0.0, rs)
                floor = get_arousal_floor(state, rs)
                notes.append(eff_name + ':insemination orgasm — arousal reset to floor=' + str(floor))
                # Mark for next-turn afterglow — any gated effect with requires_event
                # + arousal_reset_on gets this treatment automatically.
                post_flags = state.setdefault('_post_orgasm_effects', {})
                post_flags[eff_name] = True
        if gate.get('blocks_orgasm') and orgasm_this_turn:
            denied_this_turn = True
            notes.append(eff_name + ':orgasm blocked')

    for eff_name in effects:
        mech = em.get(eff_name, {})
        tb   = mech.get('trigger_behavior', {})
        if not tb:
            continue
        trigger = tb.get('trigger', '')

        if trigger == 'directive' and events.get('directive'):
            run_roll(state, eff_name, notes, rs)

        elif trigger == 'active_no_event':
            skip_event = tb.get('skip_on_event')
            grace      = tb.get('skip_on_grace', False) and eff_name in newly_added
            if not grace and not (skip_event and events.get(skip_event)):
                run_roll(state, eff_name, notes, rs)
            reset_on = tb.get('reset_on')
            if reset_on and events.get(reset_on):
                start = int(mech.get('start_dc', 12))
                set_effect_dc(state, eff_name, start)
                state.setdefault('effect_locks', {})[eff_name] = False
                notes.append(eff_name + ' DC reset to ' + str(start))

        elif trigger == 'linked_orgasm':
            linked_eff   = tb.get('linked_effect', '')
            linked_event = tb.get('linked_orgasm_event', '')
            has_stage    = get_effect_stage(state, eff_name) > 0
            if (linked_eff in effects or has_stage) and events.get(linked_event):
                gate = orgasm_rules.get(linked_eff, {})
                if gate.get('arousal_reset_on') and events.get(gate['arousal_reset_on']):
                    set_arousal(state, 0.0, rs)
                    floor = get_arousal_floor(state, rs)
                    notes.append(linked_eff + ':orgasm+arousal reset to floor=' + str(floor))
                if not is_locked(state, eff_name):
                    result = run_roll(state, eff_name, notes, rs)
                    if result == 'fail':
                        advance_stage(state, eff_name, notes, rs, to_db=tb.get('permanent_to_db', False))

        elif trigger == 'orgasm_attempt':
            # Roll is handled by _roll_breeder_resist in _check_orgasm_trigger.
            # Here we only handle reset_on (e.g. creampie resets the DC).
            reset_on = tb.get('reset_on')
            if reset_on and events.get(reset_on):
                start = int(mech.get('start_dc', 15))
                set_effect_dc(state, eff_name, start)
                state.setdefault('effect_locks', {})[eff_name] = False
                notes.append(eff_name + ' DC reset to ' + str(start))

        elif trigger == 'orgasm_denied' and denied_this_turn:
            run_roll(state, eff_name, notes, rs)
            reset_on = tb.get('reset_on')
            if reset_on and events.get(reset_on):
                start = int(mech.get('start_dc', 12))
                set_effect_dc(state, eff_name, start)
                state.setdefault('effect_locks', {})[eff_name] = False
                notes.append(eff_name + ' DC reset on release')
            int_check = mech.get('int_check', {})
            if int_check and denied_this_turn:
                check_stat = int_check.get('check_stat', 'INT_mod')
                buff_stat  = int_check.get('buff_stat',  'WIS_mod')
                buff_amt   = int(int_check.get('buff_amount', 1))
                int_dc     = state.setdefault('denial_int_dc', int(int_check.get('start_dc', 10)))
                int_mod    = get_stat_mod(state, check_stat)
                roll       = random.randint(1, 20)
                total      = roll + int_mod
                passed     = total >= int_dc
                if passed:
                    pass_flag = int_check.get('pass_set_flag', '')
                    if pass_flag:
                        state.setdefault('flags', {})[pass_flag] = True
                    state['stats'][buff_stat] = get_stat_mod(state, buff_stat) + buff_amt
                    state['_denial_buff_stat'] = buff_stat
                    notes.append('Denial ' + check_stat + ':PASS(+' + str(buff_amt) + ' ' + buff_stat + ')')
                else:
                    fail_flag = int_check.get('fail_set_flag_false', '')
                    if fail_flag:
                        state.setdefault('flags', {})[fail_flag] = False
                    fail_mod = int(int_check.get('fail_dc_mod', -2))
                    state['denial_int_dc'] = max(4, int_dc + fail_mod)
                    notes.append('Denial ' + check_stat + ':FAIL(DC now ' + str(state['denial_int_dc']) + ')')

        elif trigger == 'message_interval':
            interval    = int(tb.get('interval', 50))
            counter_key = tb.get('counter_key', eff_name + '_msg_count')
            count       = state.get(counter_key, 0) + 1
            state[counter_key] = count
            if count % interval == 0 and not is_locked(state, eff_name):
                result = run_roll(state, eff_name, notes, rs)
                if result == 'fail':
                    advance_stage(state, eff_name, notes, rs)

        elif trigger == 'session_start':
            prefix = rs.get('engine_config', {}).get('session_roll_flag_prefix', 'session_rolled_')
            flag   = prefix + eff_name
            if not state.get('flags', {}).get(flag) and not is_locked(state, eff_name):
                result = run_roll(state, eff_name, notes, rs)
                if result == 'fail':
                    advance_stage(state, eff_name, notes, rs, to_db=tb.get('permanent_to_db', False))
                state.setdefault('flags', {})[flag] = True

    events['orgasm_this_turn'] = orgasm_this_turn
    _process_counters(state, events, effects, rs)

    for ev_name in rs.get('state_events', {}):
        if events.get(ev_name):
            _execute_state_events(ev_name, state, events, effects, notes, rs)

    # Store notes in state for debug_print to display
    if notes:
        state.setdefault('_notes_log', []).extend(notes)

    return state


# ── Stat generation ──────────────────────────────────────────────────────────

def _stat_mod(v, rs):
    cfg     = (rs or {}).get('engine_config', {}).get('stat_mod_formula', {})
    base    = int(cfg.get('base',    10))
    divisor = int(cfg.get('divisor',  2))
    return (int(v) - base) // divisor

def parse_card_stats(stats_line, rs=None):
    valid = set(rs['stat_list']) if rs and rs.get('stat_list') else None
    stats = {}
    for token in (stats_line or '').split():
        if ':' in token:
            k, _, v = token.partition(':')
            k = k.strip().upper()
            if valid is None or k in valid:
                try:
                    stats[k] = max(1, min(20, int(v.strip())))
                except ValueError:
                    pass
    expected = len(valid) if valid else 6
    if len(stats) < expected:
        return None
    result = dict(stats)
    for k, v in stats.items():
        result[k + '_mod'] = _stat_mod(v, rs)
    return result

def run_statgen(system_text, rs=None):
    stat_names = rs['stat_list'] if rs and rs.get('stat_list') else []
    stats    = {s: 10 for s in stat_names}
    combined = system_text.lower()
    for sig in (rs.get('statgen_signals') or [] if rs else []):
        s = sig.get('stat', '')
        if s in stats and any(k in combined for k in sig.get('keywords', [])):
            stats[s] = max(6, min(14, stats[s] + int(sig.get('delta', 0))))
    result = dict(stats)
    for k, v in stats.items():
        result[k + '_mod'] = _stat_mod(v, rs)
    print('[STATGEN] ' + str(stats))
    return result


# ── Formatting helpers ───────────────────────────────────────────────────────

def fmt_stats(stats):
    if not stats:
        return '(none)'
    parts = []
    for s in (k for k in stats if not k.endswith('_mod')):
        mod  = stats.get(s + '_mod', 0)
        sign = '+' if mod >= 0 else ''
        parts.append(s + '=' + str(stats[s]) + '(' + sign + str(mod) + ')')
    return ' '.join(parts)

def fmt_effects(state):
    effects = state.get('active_effects') or []
    if not effects:
        return 'none'
    parts = []
    for eff in effects:
        dc     = state.get('effect_dcs',    {}).get(eff)
        stage  = state.get('effect_stages', {}).get(eff)
        locked = state.get('effect_locks',  {}).get(eff)
        info   = eff
        if locked:
            info += '[LOCKED' + ((' s=' + str(stage)) if stage else '') + ']'
        elif dc is not None:
            info += '[DC=' + str(dc) + ((' s=' + str(stage)) if stage else '') + ']'
        parts.append(info)
    return ', '.join(parts)

def fmt_persona_header(persona, persona_state, char_name, rs=None):
    stats    = persona_state.get('stats', {})
    rel      = persona_state.get('relationships', {}).get(char_name.lower(), {})
    defaults = (rs or {}).get('relationship_schema', {}).get('default_fields', {})
    stat_str = ' '.join(
        s + '=' + str(stats[s]) + '(' + ('+' if stats.get(s+'_mod', 0) >= 0 else '') +
        str(stats.get(s+'_mod', 0)) + ')'
        for s in stats if not s.endswith('_mod')
    )
    rel_parts = []
    for k, v in rel.items():
        if v != defaults.get(k) and v is not None and v != '' and v != 0 and v is not False:
            rel_parts.append(str(k) + '=' + str(v))
    rel_str = ' | '.join(rel_parts) if rel_parts else 'new'
    return 'Persona:' + persona + ' ' + stat_str + ' | ' + char_name + '_rel: ' + rel_str


# ── Persona relationship ─────────────────────────────────────────────────────

def update_persona_relationship(persona_state, char_name, events, char_state, rs=None):
    schema       = (rs or {}).get('relationship_schema', {})
    default_flds = schema.get('default_fields', {})
    rels = persona_state.setdefault('relationships', {})
    rel  = rels.setdefault(char_name.lower(), dict(default_flds))

    char_effects = char_state.get('active_effects', [])
    flags        = char_state.get('flags', {})

    for event_key, field in schema.get('event_increments', {}).items():
        if events.get(event_key):
            rel[field] = rel.get(field, 0) + 1

    for flag_key, setter in schema.get('flag_sets', {}).items():
        if flags.get(flag_key):
            rel[setter['field']] = setter['value']

    orgasm_field  = schema.get('orgasm_increment', '')
    orgasm_events = schema.get('orgasm_events', [])
    orgasm_reqs   = schema.get('orgasm_requires_any_effect', {})
    orgasm_fired  = False
    for ev in orgasm_events:
        if not events.get(ev):
            continue
        req = orgasm_reqs.get(ev)
        if req and not any(e in char_effects for e in req):
            continue
        orgasm_fired = True; break
    if orgasm_fired:
        rel[orgasm_field] = rel.get(orgasm_field, 0) + 1

    for event_key, setter in schema.get('event_sets', {}).items():
        if events.get(event_key):
            field = setter['field']
            if setter.get('only_if_unset') and rel.get(field):
                continue
            rel[field] = events[event_key] if setter.get('from_event') else setter.get('value')

    dynamics = schema.get('dynamics', {})
    for eff, dynamic_val in dynamics.items():
        if eff in char_effects:
            rel['dynamic'] = dynamic_val
            break

    return persona_state


# ── Header builder ───────────────────────────────────────────────────────────

def build_header(name, card_sex, state, notes, events, rs, persona=None, persona_state=None):
    eff_sex  = current_sex(state, card_sex, rs)
    genitals = current_genitals(state, card_sex, rs)
    pill     = state.get('active_pill') or ''
    lines    = []

    form_line = name + ' is currently ' + eff_sex + ', genitals: ' + genitals
    if pill:
        form_line += ', pill: ' + pill
    lines.append(form_line)

    resolved = state.get('resolved_body')
    if resolved:
        parts = []
        for k in rs.get('body_result_tag', {}).get('fields', []):
            if k in resolved:
                parts.append(k + ': ' + resolved[k])
        if parts:
            lines.append('Confirmed body: ' + ', '.join(parts))

    effects = state.get('active_effects') or []
    if effects:
        lines.append('Active effects: ' + ', '.join(effects))

    orgasm_gates = rs['orgasm_rules'].get('gates', {})

    # Build the set of gated effects whose unlock event fired this turn.
    # Used to suppress their injection_rule and inject an unlock instead.
    unlocked_effects = {
        eff for eff, gate in orgasm_gates.items()
        if eff in effects
        and gate.get('requires_event')
        and events.get(gate['requires_event'])
    }

    for eff in effects:
        # Suppress the standing "no orgasm" injection_rule for any effect whose
        # gate event just fired — the unlock below replaces it.
        if eff in unlocked_effects:
            continue
        rule = rs['effect_mechanics'].get(eff, {}).get('injection_rule')
        if rule:
            lines.append(rule)

    # Orgasm unlock — one-turn override for each effect whose gate event fired.
    for eff in unlocked_effects:
        gate = orgasm_gates[eff]
        unlock_text = gate.get('unlock_text') or (
            eff.upper() + ' UNLOCK (this turn only): '
            + gate.get('requires_event', 'trigger').replace('_', ' ')
            + ' received — orgasm IS allowed. '
            'Write the character climaxing. '
            'Keep it to 1–2 sentences before continuing the scene.'
        )
        lines.append(unlock_text)

    flags = state.get('flags') or {}
    for df in rs.get('display_flags', []):
        if flags.get(df['flag']):
            lines.append(df['label'])

    pill_desc = state.get('_pill_descriptor_this_turn')
    if pill_desc:
        card_body = state.get('card_body', {})
        lines.append('')
        lines.append(build_transformation_guidance(pill_desc, card_body, card_sex, rs))
        # Update card_body to post-transformation target values
        modifier = pill_desc.get('body_modifier')
        color    = pill_desc.get('color', '')
        if modifier and color:
            bm     = rs.get('body_modifiers', {})
            target = bm.get(color, {}).get('modifiers', {}).get(modifier, {})
            if target:
                state['card_body'] = {
                    'height_str': target.get('height', ''),
                    'weight':     target.get('weight', ''),
                    'build_keywords': [b.strip() for b in target.get('build', '').split(',')] if target.get('build') else [],
                    'bust':       target.get('bust', ''),
                    'modifier':   modifier,
                }

    # ── Fragment system ─────────────────────────────────────────────────────
    # d20-roll fragment tables produce sex-aware, stat-gated phrases
    # that compose into a character state block.
    # Suppress on pill_taken turns (and regens of pill turns) — transformation
    # guidance needs the model's full attention; fragment prose competes with it
    # and causes the model to ignore the transformation instructions.
    if events.get('pill_taken') or state.get('_pill_descriptor_this_turn'):
        flavor_blocks = []
    else:
        flavor_blocks = evaluate_fragments(state, events, card_sex, random.random)

    # One-turn afterglow bridge — fires the turn AFTER a gated-effect orgasm.
    # _post_orgasm_effects is a dict set by process_events; we consume it here.
    post_orgasm_map = state.pop('_post_orgasm_effects', {})
    for eff_name, fired in post_orgasm_map.items():
        if not fired:
            continue
        if eff_name not in effects:
            continue
        gate = orgasm_gates.get(eff_name, {})
        req_ev = gate.get('requires_event', '')
        # Don't show afterglow on the same turn as another orgasm of this type
        if req_ev and events.get(req_ev):
            continue
        afterglow = gate.get('afterglow_text') or (
            eff_name.upper() + ' AFTERGLOW: The orgasm was last turn. '
            'Character is in the immediate aftermath — calm, warm, slightly dazed. '
            'The desperate need is gone. Body is settling. '
            'Do not re-narrate the climax. Write the quiet that follows: '
            'steadying breath, the weight of the other person, the warmth that has not faded yet. '
            'This is the peace before the next cycle begins.'
        )
        # Insert afterglow at slot 1 (after mechanic rule), suppress blocks
        # that would re-narrate what already happened last turn.
        tag_upper = eff_name.upper()
        filtered = [b for b in flavor_blocks
                    if (tag_upper + ' ORGASM') not in b and 'POST-ORGASM' not in b]
        flavor_blocks = ([filtered[0]] + [afterglow] + filtered[1:]
                         if filtered else [afterglow])

    if flavor_blocks:
        lines.append('')
        lines.extend(flavor_blocks)

    for rule in rs.get('system_rules', []):
        lines.append(rule)

    return '\n'.join(lines)


# ── Debug printer ────────────────────────────────────────────────────────────

def debug_print(sk, name, card_sex, state, events, rs, persona=None, persona_state=None):
    ar       = get_arousal(state)
    ar_floor = get_arousal_floor(state, rs)
    mx       = int(rs['arousal_system'].get('max', 60))
    effects  = state.get('active_effects', [])
    no_decay = set(rs['arousal_system'].get('no_decay_effects', []))
    exempt   = [e for e in effects if e in no_decay]
    ar_pen   = arousal_roll_penalty(state, rs)
    pen_str  = ('AUTO-FAIL' if ar_pen == 'auto_fail' else (str(ar_pen) if ar_pen else 'none'))
    print('=' * 65)
    print('[PROXY] ' + sk + ' t=' + str(state.get('turn')))
    print('  char    : ' + name + ' card=' + card_sex + ' form=' + current_sex(state, card_sex, rs))
    print('  pill    : ' + str(state.get('active_pill')))
    _rb = state.get('resolved_body')
    _cb = state.get('card_body', {})
    if _rb:
        _bparts = []
        for _bk in ('height', 'weight', 'bust', 'build'):
            if _bk in _rb: _bparts.append(_bk + '=' + str(_rb[_bk]))
        if _bparts: print('  body    : ' + ', '.join(_bparts) + ' [confirmed]')
    elif _cb.get('height_str') or _cb.get('modifier'):
        _bparts = []
        if _cb.get('height_str'): _bparts.append(_cb['height_str'])
        if _cb.get('weight'):     _bparts.append(str(_cb['weight']))
        if _cb.get('bust'):       _bparts.append(_cb['bust'])
        if _cb.get('modifier'):   _bparts.append('mod=' + _cb['modifier'])
        if _bparts: print('  body    : ' + ', '.join(_bparts))
    if state.get('_pending_pill'):
        print('  pending : ' + str(state.get('_pending_pill')) + ' ' + str(state.get('_pending_pill_desc', {})))
    print('  effects : ' + fmt_effects(state))
    gate     = state.get('_arousal_gate')
    gate_str = ''
    if gate:
        stat_part = ('+' if gate.get('mod', 0) >= 0 else '') + str(gate.get('mod', 0))
        gate_str = (' | gate d6=' + str(gate.get('d6', '?')) + '->' + str(gate.get('d6_stat', '?'))
                    + ' d20=' + str(gate['roll']) + stat_part
                    + '=' + str(gate.get('total', gate.get('eff_roll', '?'))) + ' vs DC' + str(gate['dc'])
                    + ' → ' + ('HELD at <' + str(gate['threshold']) if gate['result'] == 'held'
                              else 'CROSSED ' + str(gate['threshold'])) + ')'
                    + ' (next DC=' + str(state.get('_arousal_gate_dcs', {}).get(str(gate['threshold']), '?')) + ')'
                    + (' fails=' + str(state.get('_arousal_gate_fail_count', 0)) if state.get('_arousal_gate_fail_count') else ''))
    print('  arousal : ' + str(ar) + '/' + str(mx) +
          ' (' + arousal_label(ar, rs) + ')' +
          ' floor=' + str(ar_floor) +
          ' pen=' + pen_str +
          (' [no-decay:' + ','.join(exempt) + ']' if exempt else '') +
          gate_str)
    print('  stats   : ' + fmt_stats(state.get('stats')))
    print('  flags   : ' + str({k: v for k, v in (state.get('flags') or {}).items() if v not in (False, None, 0, '')}))
    print('  events  : ' + (', '.join(k for k, v in events.items() if v) if events else 'none'))
    roll_log = state.get('roll_log', [])
    if roll_log:
        print('  rolls   :')
        for entry in roll_log:
            print('    ' + entry)
    else:
        print('  rolls   : none this turn')
    active_effects = state.get('active_effects', [])
    if active_effects:
        print('  eff detail:')
        em = rs.get('effect_mechanics', {})
        for eff in active_effects:
            dc     = state.get('effect_dcs', {}).get(eff)
            stage  = state.get('effect_stages', {}).get(eff, 0)
            locked = state.get('effect_locks',  {}).get(eff, False)
            mech   = em.get(eff, {})
            tb     = mech.get('trigger_behavior', {})
            trigger = tb.get('trigger', '(no trigger)') if tb else '(no trigger)'
            parts  = [eff, 'trigger=' + trigger]
            if dc is not None: parts.append('DC=' + str(dc))
            if stage: parts.append('stage=' + str(stage))
            if locked: parts.append('LOCKED')
            print('    ' + ' '.join(parts))
    print('=' * 65)
    state['roll_log'] = []
    note_log = state.pop('_notes_log', [])
    if note_log:
        print('  notes   :')
        for n in note_log:
            print('    ' + n)

    if persona and persona_state:
        p_stats   = persona_state.get('stats', {})
        p_effects = persona_state.get('effects', [])
        p_pill    = persona_state.get('active_pill')
        rel       = persona_state.get('relationships', {}).get(name.lower(), {})
        print('-' * 65)
        print('[PERSONA] ' + persona)
        print('  stats   : ' + fmt_stats(p_stats))
        print('  pill    : ' + str(p_pill))
        print('  effects : ' + (', '.join(p_effects) if p_effects else 'none'))
        rel_parts    = []
        rel_defaults = (rs or {}).get('relationship_schema', {}).get('default_fields', {})
        for k, v in rel.items():
            if v != rel_defaults.get(k) and v is not None and v != '' and v != 0 and v is not False:
                rel_parts.append(str(k) + '=' + str(v))
        print('  rel[' + name + ']: ' + (', '.join(rel_parts) if rel_parts else 'new'))
        print('-' * 65)


# ── Transformation prose scanner ─────────────────────────────────────────────
def scan_transformation_prose(text, rs=None):
    """
    Scan model response prose after a transformation turn.
    Extracts body measurements without requiring structured tag output.
    Returns dict with any of: height, weight, bust, build.
    """
    import re
    result = {}

    # Height — 5'1", 5'2"
    m = re.search(r"(\d+)'(\d+)", text)
    if m:
        result['height'] = m.group(1) + "'" + m.group(2) + '"'

    # Weight — 100lbs, 105 lbs
    m = re.search(r'(\d+)\s*lbs?', text, re.IGNORECASE)
    if m:
        result['weight'] = m.group(1) + 'lbs'

    # Bust — B-cup, B cup, DD cup, A cups
    m = re.search(r'\b([A-Fa-f]{1,2}(?:\+|-)?)[\s-]?cups?\b', text, re.IGNORECASE)
    if m:
        letter = m.group(1).rstrip('-').upper()
        result['bust'] = letter + '-cup'

    # Build keywords
    build_kws = (rs or {}).get('card_scan', {}).get('build_keywords', [
        'petite', 'slim', 'slender', 'slight', 'lean', 'athletic', 'toned',
        'muscular', 'curvy', 'curvaceous', 'hourglass', 'full', 'delicate',
        'proportional', 'heavy', 'stocky', 'broad',
    ])
    found = [k for k in build_kws if re.search(r'\b' + k + r'\b', text, re.IGNORECASE)]
    if found:
        result['build'] = ', '.join(found[:3])

    return result

def handle_response(assistant_text: str, state: dict, events: dict, rs: dict) -> None:
    """
    Called by the proxy after the model responds.
    Handles anything that needs to happen based on the response content.
    Currently: scans prose for body measurements on transformation turns.
    Add any future response-side logic here — proxy stays untouched.
    """
    if events.get('pill_taken'):
        body_result = scan_transformation_prose(assistant_text, rs)
        # If model didn't state numbers, fall back to target body from pill descriptor
        if not body_result or not any(k in body_result for k in ('height', 'weight', 'bust')):
            desc     = events.get('pill_descriptor') or {}
            color    = desc.get('color', '')
            modifier = desc.get('body_modifier')
            if modifier and color:
                targets = (rs.get('body_modifiers', {}).get(color, {})
                           .get('modifiers', {}).get(modifier, {}))
                if targets:
                    fallback = {}
                    if 'height' in targets: fallback['height'] = targets['height'].split('-')[0].strip()
                    if 'weight' in targets: fallback['weight'] = targets['weight'].split('-')[0].strip()
                    if 'bust'   in targets: fallback['bust']   = targets['bust'].split(',')[0].strip()
                    if 'build'  in targets: fallback['build']  = targets['build'].split(',')[0].strip()
                    if fallback:
                        body_result = {**fallback, **(body_result or {})}
                        print('[BODY_SCAN] fallback to target body:', body_result)
        if body_result:
            state['resolved_body'] = body_result



def process_turn(system_text: str, messages: list, state: dict, persona_state: dict,
                 persona: str, session_key: str, scan_last: int = 12,
                 debug: bool = False, rs: dict = None) -> dict:
    """
    Single entry point for the proxy to call each turn.
    Takes raw request data, returns everything the proxy needs to forward the request.

    Returns dict:
        name        — character name
        sex         — card sex
        state       — updated state
        persona_state — updated persona state
        header      — injection block string
        ok          — False if request should passthrough (missing name/sex)
    """
    name = extract_card_name(system_text, rs)
    sex  = extract_card_sex(system_text, rs)
    if not name or not sex:
        return {'ok': False}

    # Regen/swipe detection — hash the last user message.
    # If it matches last turn's hash, this is a regenerate: skip increment and reuse prior state.
    last_user_msg = next(
        (m.get('content', '') for m in reversed(messages) if m.get('role') == 'user'), ''
    )
    import hashlib as _hl
    last_hash = _hl.md5(last_user_msg[:500].encode('utf-8', errors='ignore')).hexdigest()
    is_regen  = (last_hash == state.get('_last_user_hash'))
    if not is_regen:
        state['turn']           = int(state.get('turn', 0)) + 1
        state['_last_user_hash'] = last_hash

    # Stat generation — first turn only
    flags        = state.setdefault('flags', {})
    statgen_flag = rs.get('engine_config', {}).get('statgen_flag', 'statgen_done')
    if not flags.get(statgen_flag):
        persona_lore_stats = rs.get('personas', {}).get(name)
        if persona_lore_stats:
            state['stats']     = dict(persona_lore_stats)
            state['card_body'] = scan_card_body(system_text, rs)
            print('[STATGEN] Persona stats used for ' + name)
        else:
            card_text  = _card_section(system_text)
            stats_line = extract_card_stats(card_text, rs)
            parsed     = parse_card_stats(stats_line, rs) if stats_line else None
            if parsed:
                state['stats'] = parsed
                print('[STATGEN] Card stats used for ' + name + ': ' + stats_line)
            else:
                state['stats'] = run_statgen(card_text, rs)
                print('[STATGEN] Keyword fallback for ' + name)
            state['card_body'] = scan_card_body(system_text, rs)
        flags[statgen_flag] = True
        if state['card_body']:
            print('[BODY] ' + str(state['card_body']))

    if is_regen:
        if debug:
            print('[PROXY] regen detected — skipping turn increment and event processing')
        return {
            'ok':            True,
            'name':          name,
            'sex':           sex,
            'state':         state,
            'persona_state': persona_state,
            'events':        {},
            'header':        build_header(name, sex, state, [], {}, rs, persona, persona_state),
        }

    # Clear pill descriptor from previous turn (kept for regen re-injection)
    state.pop('_pill_descriptor_this_turn', None)

    # Clear per-turn arousal gate flags
    state.pop('_arousal_gate_done', None)
    state.pop('_arousal_gate_crossed_to', None)
    state.pop('_arousal_gate', None)

    # Stash card_sex for use by grow_arousal negative blocks
    state['_card_sex'] = sex

    # Arousal scan — last 2 chat messages only, skip turn 1
    recent = [m for m in messages[-scan_last:]
              if isinstance(m, dict) and m.get('role') != 'system']
    persona_markers = tuple(rs['card_format'].get('strip_markers', []))
    chat_only = [
        m for m in recent
        if m.get('role') in ('user', 'assistant')
        and not any(marker in (m.get('content') or '') for marker in persona_markers)
    ]
    arousal_scan_msgs = chat_only[-2:] if len(chat_only) >= 2 else chat_only
    if state.get('turn', 1) > 1:
        apply_arousal_decay(state, rs)
        apply_effect_passives(state, rs, debug=debug)
        scan_arousal(arousal_scan_msgs, state, rs, debug=debug)

    # Persona stats from lore
    persona_state['stats'] = rs.get('personas', {}).get(persona, persona_state.get('stats', {}))

    # Event detection and state processing
    notes = []
    recent_for_intake = (recent[:-1] if recent and recent[-1].get('role') == 'assistant'
                         else recent)
    events = detect_events(recent_for_intake, state, sex, rs, debug=debug)
    state  = process_events(state, events, sex, notes, rs)

    persona_state = update_persona_relationship(persona_state, name, events, state, rs)

    # Clean up one-turn buffs
    denial_buff_stat = state.pop('_denial_buff_stat', None)
    if denial_buff_stat:
        state['stats'][denial_buff_stat] = get_stat_mod(state, denial_buff_stat) - 1

    if debug:
        debug_print(session_key, name, sex, state, events, rs, persona, persona_state)

    header = build_header(name, sex, state, notes, events, rs, persona, persona_state)
    if debug:
        print('[INJECT] (' + str(len(header)) + ' chars)\n' + header + '\n')

    return {
        'ok':           True,
        'name':         name,
        'sex':          sex,
        'state':        state,
        'persona_state': persona_state,
        'events':       events,
        'header':       header,
    }


def extract_identity(system_text: str, rs: dict) -> dict:
    """Extract name and sex from system text. Called by proxy for session routing."""
    return {
        'name': extract_card_name(system_text, rs),
        'sex':  extract_card_sex(system_text, rs),
    }


def inject_header(req_json: dict, header: str, max_inject: int, rs: dict) -> dict:
    """Inject the state header into the last user message. Fully lore-owned."""
    if not header or not header.strip():
        return req_json
    messages = req_json.get('messages', [])
    if not isinstance(messages, list):
        return req_json
    header = header[:max_inject]
    ec     = rs.get('engine_config', {})
    prefix = ec.get('injection_prefix', '\n\n[STATE]\n')
    suffix = ec.get('injection_suffix', '\n[/STATE]')
    for i in range(len(messages) - 1, -1, -1):
        if messages[i].get('role') == 'user':
            existing = messages[i].get('content') or ''
            messages[i]['content'] = existing + prefix + header + suffix
            req_json['messages'] = messages
            return req_json
    req_json['messages'] = [{'role': 'system', 'content': header}] + messages
    return req_json


# ── Entry point called by the proxy ─────────────────────────────────────────
def load() -> Dict:
    """Compile and return the ruleset.  Proxy calls lore_module.load()."""
    return compile_ruleset(_LORE_RAW)